-- ============================================================================
-- SalzGuide — Event-Anker (jährliche „Pflicht-Highlights" im Land Salzburg)
-- Zweck: ERINNERUNG/Checkliste für die KI-Wochenrecherche, damit kein großes
-- jährliches Event übersehen wird. Enthält KEINE konkreten Datteln (nur Monats-
-- Zeitfenster + offizielle Quelle) — Datum/Uhrzeit werden pro Woche live verifiziert.
-- Über das Admin-Panel pflegbar (kein Code-Deploy nötig).
-- Idempotent: kann gefahrlos mehrfach ausgeführt werden. Im Supabase SQL-Editor ausführen.
-- ============================================================================

-- ----------------------------------------------------------------------------
-- 1. Tabelle (nutzt das bestehende enum event_category aus 0009_events.sql)
-- ----------------------------------------------------------------------------
create table if not exists public.event_anchors (
  id          uuid primary key default gen_random_uuid(),
  key         text unique not null,          -- stabiler slug (z.B. "electric-love")
  name        text not null,
  category    event_category not null default 'kultur',
  region      text not null default 'ganzes Land',
  months      int[] not null default '{}',   -- Monate (1–12), in denen es typisch läuft
  timing      text not null default '',       -- Zeitfenster in Worten (KEIN Beleg)
  url         text not null default '',       -- offizielle Quelle zum Verifizieren
  free        text not null default 'nein' check (free in ('ja','nein','teils')),
  why         text not null default '',       -- 1 Satz: warum für die Zielgruppe wichtig
  note        text,                           -- Vorbehalt (z.B. „nur alle 2 Jahre")
  active      boolean not null default true,  -- im Admin an-/abschaltbar
  sort_order  int not null default 0,
  created_at  timestamptz not null default now(),
  updated_at  timestamptz not null default now()
);

comment on table public.event_anchors is
  'Jährliche Anker-Events: Erinnerung für die KI-Wochenrecherche. Nur Zeitfenster + Quelle, KEINE festen Datteln — die werden pro Woche live verifiziert.';
comment on column public.event_anchors.months is
  'Monate 1–12, in denen das Event typischerweise stattfindet -> Filter für die Zielwoche.';

create index if not exists event_anchors_active_idx on public.event_anchors (active);

-- updated_at pflegen (Funktion aus 0001_init.sql)
drop trigger if exists event_anchors_set_updated_at on public.event_anchors;
create trigger event_anchors_set_updated_at
  before update on public.event_anchors
  for each row execute function public.set_updated_at();

-- ----------------------------------------------------------------------------
-- 2. Row Level Security (Default deny; nur Admin liest/schreibt via UI).
--    Die KI-Wochenrecherche liest über den service_role-Key (umgeht RLS).
-- ----------------------------------------------------------------------------
alter table public.event_anchors enable row level security;

drop policy if exists "event_anchors_admin_all" on public.event_anchors;
create policy "event_anchors_admin_all" on public.event_anchors
  for all to authenticated
  using (public.is_admin()) with check (public.is_admin());

-- ----------------------------------------------------------------------------
-- 3. Seed (idempotent: on conflict (key) do nothing -> überschreibt Admin-Edits NIE)
--    >>> Wird weiter unten in diesem File eingefügt (aus event-anchors.ts generiert). <<<
-- ----------------------------------------------------------------------------
on conflict (key) do nothing;
